#include <stdbool.h>
#include <stdlib.h>

typedef int ElemType;
typedef struct LNode {
    ElemType data;
    struct LNode *next;
} LNode, *LinkList;

bool InitList(LinkList *L) {
    *L = (LNode *)malloc(sizeof(LNode));
    if (*L == NULL) {
        return false;
    }
    (*L)->next = NULL;
    return true;
}

bool CreateListTail(LinkList *L, const ElemType a[], int n) {
    if (!InitList(L)) {
        return false;
    }
    LNode *r = *L;
    for (int i = 0; i < n; ++i) {
        LNode *s = (LNode *)malloc(sizeof(LNode));
        if (s == NULL) {
            return false;
        }
        s->data = a[i];
        s->next = NULL;
        r->next = s;
        r = s;
    }
    return true;
}

bool CreateListHead(LinkList *L, const ElemType a[], int n) {
    if (!InitList(L)) {
        return false;
    }
    for (int i = 0; i < n; ++i) {
        LNode *s = (LNode *)malloc(sizeof(LNode));
        if (s == NULL) {
            return false;
        }
        s->data = a[i];
        s->next = (*L)->next;
        (*L)->next = s;
    }
    return true;
}
